function results = arAnalyseLhsResults(threshold)
% arAnalyseLhsResults Analyse and group LHS fit results by chi2 similarity.
%
%   results = arAnalyseLhsResults(threshold)
%
%   This function analyzes the chi2 values from the global 'ar' structure,
%   typically generated by multistart parameter fits with 'arFitLHS'.
%   It groups chi2 values into distinct "levels" based on a user-defined
%   threshold, counts the number of unique levels, and summarizes the
%   population of each level.
%
%   Input:
%       threshold (double, optional) - Maximum difference between chi2 values
%           to be considered part of the same level. Default is 0.01.
%
%   Output:
%       results (struct) - Structure with analysis results:
%           .chi2_list               - Original chi2 values (from ar.chi2s)
%           .chi2_sorted             - Sorted chi2 values (ascending, NaNs last)
%           .iSort                   - Indices mapping sorted to original order
%           .levelLink               - Level assignment for each chi2 value
%           .threshold               - Threshold used for grouping
%           .nLHS                    - Total number of chi2 values
%           .nSuccess                - Number of successful (finite) fits
%           .nLevels                 - Number of distinct chi2 levels
%           .nLevelsRepeated         - Number of levels with >1 member
%           .levelVals               - Representative chi2 value for each level
%           .levelPopulation         - Number of fits in each level
%           .totalPopulationRepeated - Total number of fits in repeated levels
%           .lowestLevelPopulation   - Number of fits in the lowest chi2 level
%           .lowestLevelVal          - Value of the lowest chi2 level
%           .fitTimes                - Fit times for each LHS run (ar.timing)
%           .totalFitTime            - Total time for all fits
%           .medianFitTime           - Median fit time
%           .exitflag                - Exit flags for each fit (ar.exitflag)
%
%   Example:
%       results = arAnalyseLhsResults(0.01);

arguments
    threshold (1,1) double {mustBeNumeric} = 0.01
end

global ar

% Check for required field in global structure
if ~isfield(ar, 'chi2s')
    error('Missing field ar.chi2s, please run arFitLHS first.');
end

% Retrieve chi2 values and sort them (ascending, NaNs at the end)
chi2_list = ar.chi2s;
[chi2_sorted, iSort] = sort(chi2_list);

% Identify successful fits (finite chi2 values)
qSuccess = isfinite(chi2_sorted);
chi2_sorted_success = chi2_sorted(qSuccess);
nSuccess = sum(qSuccess);

% Initialize level grouping variables
levelVals = [];
levelPopulation = [];
levelLink = NaN(1, length(chi2_sorted));

if nSuccess == 0
    % No successful fits: set outputs to NaN
    nLevels = NaN;
    nLevelsRepeated = NaN;
    totalPopulationRepeated = NaN;
    lowestLevelVal = NaN;
    lowestLevelPopulation = NaN;
else
    % Start with the first successful chi2 as the first level
    levelVals = chi2_sorted_success(1);
    levelPopulation = 1;
    nLevels = 1;
    levelLink(iSort(1)) = 1;

    % Group chi2 values into levels based on the threshold
    for i = 2:length(chi2_sorted_success)
        % If difference to previous value exceeds threshold, start new level
        if abs(chi2_sorted_success(i) - chi2_sorted_success(i-1)) > threshold
            nLevels = nLevels + 1;
            levelVals(end+1) = chi2_sorted_success(i); %#ok<AGROW>
            levelPopulation(end+1) = 1;
        else
            % Otherwise, increment population of current level
            levelPopulation(end) = levelPopulation(end) + 1;
        end
        levelLink(iSort(i)) = nLevels;
    end

    % Count levels with more than one member (potential local optima)
    nLevelsRepeated = sum(levelPopulation > 1);
    totalPopulationRepeated = sum(levelPopulation(levelPopulation > 1));

    % Identify the lowest chi2 level (potential global optimum)
    lowestLevelVal = levelVals(1);
    lowestLevelPopulation = levelPopulation(1);
end

% Assemble results structure
results = struct();
results.chi2_list = chi2_list;
results.chi2_sorted = chi2_sorted;
results.iSort = iSort;
results.levelLink = levelLink;
results.threshold = threshold;
results.nLHS = length(chi2_sorted);
results.nSuccess = nSuccess;
results.nLevels = nLevels;
results.nLevelsRepeated = nLevelsRepeated;
results.levelVals = levelVals;
results.levelPopulation = levelPopulation;
results.totalPopulationRepeated = totalPopulationRepeated;
results.lowestLevelPopulation = lowestLevelPopulation;
results.lowestLevelVal = lowestLevelVal;
results.fitTimes = ar.timing;
results.totalFitTime = sum(ar.timing);
results.medianFitTime = median(ar.timing);
results.exitflag = ar.exitflag;

end
